import java.util.Scanner;

public class SecureBufferProcessing {

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        System.out.print("Enter a string: ");
        String input = scanner.nextLine(); // Use nextLine() instead of next() to read the entire line

        // Validate input length before processing
        if (input.length() > 10) {
            System.out.println("Input exceeds maximum allowed length.");
            return;
        }

        // Securely copy input into buffer
        byte[] buffer = new byte[10];
        byte[] inputBytes = input.getBytes();

        for (int i = 0; i < Math.min(buffer.length, inputBytes.length); i++) {
            buffer[i] = inputBytes[i];
        }

        System.out.println("Input successfully processed.");
    }
}

### Explanation:
취약유형: Buffer Overflow
